  ('HR-ICF-001', 'hr', 'Internal Complaint Form', '[{"type": "paragraph", "text": "Harassment  ·  Discrimination  ·  Workplace Misconduct  ·  Safety Concerns"}, {"type": "paragraph", "text": "YOUR RIGHTS ARE PROTECTED. Gothamhalal strictly prohibits retaliation against any employee who in good faith reports a concern. Filing this form will not negatively affect your employment."}, {"type": "paragraph", "text": "This form will be reviewed exclusively by the Director of Operations and, if needed, the Co-Founders & CEOs. Your identity will be protected to the greatest extent possible."}, {"type": "heading", "level": "h1", "text": "Complainant Information"}, {"type": "other", "role": null, "text": "Your Full Name (or write ''Anonymous'')"}, {"type": "other", "role": null, "text": "Position / Role"}, {"type": "other", "role": null, "text": "Date of This Form"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Best Way to Reach You"}, {"type": "other", "role": null, "text": "Shift Assignment"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Your Full Name (or write ''Anonymous'')", "Position / Role", "Date of This Form"], ["", "", ""], ["Best Way to Reach You", "Shift Assignment", ""], ["", "", ""]]}, {"type": "heading", "level": "h1", "text": "Nature of Complaint"}, {"type": "other", "role": null, "text": "☐ Sexual Harassment"}, {"type": "other", "role": null, "text": "☐ Racial / Religious Discrimination"}, {"type": "table", "rows": [["☐ Sexual Harassment", "☐ Racial / Religious Discrimination"]]}, {"type": "other", "role": null, "text": "☐ Hostile Work Environment"}, {"type": "other", "role": null, "text": "☐ Bullying or Intimidation"}, {"type": "table", "rows": [["☐ Hostile Work Environment", "☐ Bullying or Intimidation"]]}, {"type": "other", "role": null, "text": "☐ Retaliation"}, {"type": "other", "role": null, "text": "☐ Wage / Tip Pool Dispute"}, {"type": "table", "rows": [["☐ Retaliation", "☐ Wage / Tip Pool Dispute"]]}, {"type": "other", "role": null, "text": "☐ Unsafe Working Conditions"}, {"type": "other", "role": null, "text": "☐ Theft or Fraud"}, {"type": "table", "rows": [["☐ Unsafe Working Conditions", "☐ Theft or Fraud"]]}, {"type": "other", "role": null, "text": "☐ Halal Integrity Concern"}, {"type": "other", "role": null, "text": "☐ Other: ________________________"}, {"type": "table", "rows": [["☐ Halal Integrity Concern", "☐ Other: ________________________"]]}, {"type": "heading", "level": "h1", "text": "Complaint Details"}, {"type": "paragraph", "text": "Date(s) the incident occurred: _______________"}, {"type": "paragraph", "text": "Location: _______________"}, {"type": "paragraph", "text": "Person(s) involved: _______________"}, {"type": "paragraph", "text": "Describe what happened in as much detail as possible:"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "heading", "level": "h1", "text": "Witnesses"}, {"type": "other", "role": null, "text": "Witness Name"}, {"type": "other", "role": null, "text": "Can They Be Contacted?"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "☐ Yes  ☐ No  ☐ Unknown"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "☐ Yes  ☐ No  ☐ Unknown"}, {"type": "table", "rows": [["Witness Name", "Can They Be Contacted?"], ["", "☐ Yes  ☐ No  ☐ Unknown"], ["", "☐ Yes  ☐ No  ☐ Unknown"]]}, {"type": "paragraph", "text": "Has this been reported before?  ☐ No  ☐ Yes — to whom? _______________  When? _______________"}, {"type": "paragraph", "text": "What resolution or outcome are you seeking?"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "note", "text": "Submit this form directly to the Director of Operations at mario@gothamhalal.com or in a sealed envelope marked CONFIDENTIAL."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  HR-ICF-001  ·  CONFIDENTIAL"}]'::jsonb, '{"Complainant Signature (or write 'Anonymous')","Received By — Director of Operations"}'::text[], false),
  ('OB-WL-001', 'onboarding', 'Welcome Letter', '[{"type": "paragraph", "text": "Date: ___________________________"}, {"type": "paragraph", "text": "Dear ___________________________,"}, {"type": "paragraph", "text": "Welcome to Gothamhalal. You have joined a team that believes in quality, integrity, and building something great together."}, {"type": "paragraph", "text": "My name is Ahmed Mario Almugannahi, and I serve as the Director of Operations here at Gothamhalal. On behalf of Founder & CEO Rami Ali and Co-Founder & CEO Talha Shahid, and the entire Gothamhalal leadership team — welcome. We are genuinely excited to have you on this team."}, {"type": "paragraph", "text": "Gothamhalal was built on a simple idea: New Yorkers deserve halal food that is fast, delicious, and made with real care. Every smash burger we serve is a reflection of our values — halal integrity, hospitality, and consistency. You are now a part of that mission."}, {"type": "heading", "level": "h1", "text": "What to Expect in Your First Week"}, {"type": "bullet", "text": "You will complete orientation with your manager and review the Employee Handbook."}, {"type": "bullet", "text": "You will receive your uniform and all required onboarding documents."}, {"type": "bullet", "text": "You will begin the Two-Week Training Curriculum under direct trainer supervision."}, {"type": "bullet", "text": "You will not be expected to work independently until training is complete."}, {"type": "heading", "level": "h1", "text": "Our Commitment to You"}, {"type": "paragraph", "text": "At Gothamhalal, we invest in our people. We expect professionalism, punctuality, and dedication — and in return, we commit to clear communication, fair treatment, and opportunities for growth. Every great team member who walks through our doors has a path forward here."}, {"type": "paragraph", "text": "Please read the Employee Handbook carefully. It outlines everything you need to know — our policies, your rights, compensation structure, and what we expect from every member of the Gothamhalal team. If you have questions, your manager is your first point of contact. I am also available at mario@gothamhalal.com."}, {"type": "paragraph", "text": "We are proud to have you with us. Now let''s get to work."}, {"type": "paragraph", "text": "Warmly,"}, {"type": "paragraph", "text": "<b>Ahmed Mario Almugannahi</b>"}, {"type": "paragraph", "text": "Director of Operations — Gothamhalal"}, {"type": "paragraph", "text": "mario@gothamhalal.com  |  gothamhalal.com"}, {"type": "paragraph", "text": "On behalf of Founder & CEO Rami Ali and Co-Founder & CEO Talha Shahid, and the entire Gothamhalal team."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  OB-WL-001  ·  CONFIDENTIAL"}]'::jsonb, '{}'::text[], false),
