r all employees. Update immediately if contacts change."}, {"type": "other", "role": null, "text": "Manager"}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "Direct Deposit Authorization"}, {"type": "other", "role": null, "text": "Optional but encouraged. Authorizes payroll deposit to bank account."}, {"type": "other", "role": null, "text": "Manager"}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "Uniform Agreement Form"}, {"type": "other", "role": null, "text": "Documents uniform items issued, size, and condition. Employee initials each item."}, {"type": "other", "role": null, "text": "Manager"}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "Tip Pool Acknowledgement"}, {"type": "other", "role": null, "text": "Confirms understanding and agreement with mandatory tip pool policy."}, {"type": "other", "role": null, "text": "Manager"}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "Employee Handbook Acknowledgement"}, {"type": "other", "role": null, "text": "Confirms employee received, read, and understood the Employee Handbook."}, {"type": "other", "role": null, "text": "Manager"}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "First Week Training Schedule"}, {"type": "other", "role": null, "text": "Confirms trainer assignment and training schedule for Week 1."}, {"type": "other", "role": null, "text": "Manager"}, {"type": "table", "rows": [["✓", "Document", "Purpose", "Filed By"], ["☐", "Employee Information Form", "Captures personal details, address, contact info for personnel file.", "Manager"], ["☐", "Emergency Contact Form", "Required for all employees. Update immediately if contacts change.", "Manager"], ["☐", "Direct Deposit Authorization", "Optional but encouraged. Authorizes payroll deposit to bank account.", "Manager"], ["☐", "Uniform Agreement Form", "Documents uniform items issued, size, and condition. Employee initials each item.", "Manager"], ["☐", "Tip Pool Acknowledgement", "Confirms understanding and agreement with mandatory tip pool policy.", "Manager"], ["☐", "Employee Handbook Acknowledgement", "Confirms employee received, read, and understood the Employee Handbook.", "Manager"], ["☐", "First Week Training Schedule", "Confirms trainer assignment and training schedule for Week 1.", "Manager"]]}, {"type": "heading", "level": "h1", "text": "Important Notes"}, {"type": "bullet", "text": "I-9 documents must be originals — photocopies are NOT acceptable for verification."}, {"type": "bullet", "text": "All completed forms must be placed in the employee''s personnel folder on Day 1."}, {"type": "bullet", "text": "Personnel files are confidential — stored securely and accessible only to authorized management."}, {"type": "bullet", "text": "Lost or incomplete paperwork must be resolved within 3 business days."}, {"type": "bullet", "text": "Direct deposit is available but not mandatory — check / cash arrangements must be confirmed with Director of Operations."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  OB-NHP-001  ·  CONFIDENTIAL"}]'::jsonb, '{"Manager Completing Checklist","Director of Operations Review (if required)"}'::text[], false),
  ('OB-EIF-001', 'onboarding', 'Employee Information Form', '[{"type": "paragraph", "text": "This form is confidential and will be retained in your personnel file. Please print clearly in all fields. Notify management of any changes to this information within 5 business days."}, {"type": "heading", "level": "h1", "text": "Personal Information"}, {"type": "table", "rows": [["First Name:", "Middle Name:", "Last Name:"], ["", "", ""]]}, {"type": "table", "rows": [["Preferred Name (if different):", "Date of Birth:", "Social Security # (last 4 only):"], ["", "", ""]]}, {"type": "table", "rows": [["Home Address (Street):", "City:", "State:", "Zip:"], ["", "", "", ""]]}, {"type": "table", "rows": [["Personal Phone:", "Personal Email:"], ["", ""]]}, {"type": "heading", "level": "h1", "text": "Employment Information"}, {"type": "table", "rows": [["Position / Role:", "Start Date:", "Shift Assignment:"], ["", "", ""]]}, {"type": "table", "rows": [["Part-Time or Full-Time:", "Pay Rate:", "Pay Type (hourly):"], ["", "", ""]]}, {"type": "heading", "level": "h1", "text": "Banking / Payroll"}, {"type": "table", "rows": [["Preferred Payment Method (check one): ☐ Direct Deposit  ☐ Check  ☐ Cash:"], [""]]}, {"type": "table", "rows": [["Bank Name (if direct deposit):", "Account Type (☐ Checking  ☐ Savings):"], ["", ""]]}, {"type": "heading", "level": "h1", "text": "Additional Information"}, {"type": "table", "rows": [["Are you authorized to work in the United States?   ☐ Yes  ☐ No:"], [""]]}, {"type": "table", "rows": [["Do you have any food handler certifications?  ☐ Yes  ☐ No   If yes, list::"], [""]]}, {"type": "table", "rows": [["Any scheduling limitations we should know about?:"], [""]]}, {"type": "paragraph", "text": "I certify that all information provided on this form is accurate and complete. I understand that providing false information may result in termination."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  OB-E