  ('OB-UA-001', 'onboarding', 'Uniform Agreement Form', '[{"type": "other", "role": null, "text": "Employee Full Name"}, {"type": "other", "role": null, "text": "Position"}, {"type": "other", "role": null, "text": "Start Date"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Date Uniform Issued"}, {"type": "other", "role": null, "text": "Issued By (Manager Name)"}, {"type": "other", "role": null, "text": "Shirt Size"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Employee Full Name", "Position", "Start Date"], ["", "", ""], ["Date Uniform Issued", "Issued By (Manager Name)", "Shirt Size"], ["", "", ""]]}, {"type": "heading", "level": "h1", "text": "Uniform Items Issued"}, {"type": "other", "role": null, "text": "Item"}, {"type": "other", "role": null, "text": "Quantity"}, {"type": "other", "role": null, "text": "Size / Description"}, {"type": "other", "role": null, "text": "Condition"}, {"type": "other", "role": null, "text": "Employee Initials"}, {"type": "other", "role": null, "text": "Gothamhalal Branded Shirt"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "New"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Gothamhalal Branded Shirt (2nd)"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "New"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Gothamhalal Hat / Head Covering"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "New"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Apron"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "New"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Other: ___________________"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Item", "Quantity", "Size / Description", "Condition", "Employee Initials"], ["Gothamhalal Branded Shirt", "", "", "New", ""], ["Gothamhalal Branded Shirt (2nd)", "", "", "New", ""], ["Gothamhalal Hat / Head Covering", "", "", "New", ""], ["Apron", "", "", "New", ""], ["Other: ___________________", "", "", "", ""]]}, {"type": "heading", "level": "h1", "text": "Uniform Policy Agreement"}, {"type": "bullet", "text": "Uniform items are property of Gothamhalal and must be returned upon separation of employment in clean, wearable condition."}, {"type": "bullet", "text": "Employees are responsible for keeping uniforms clean, pressed, and in good condition at all times."}, {"type": "bullet", "text": "Lost or damaged uniform items may be deducted from the final paycheck in accordance with New York State law and only with written authorization."}, {"type": "bullet", "text": "Uniforms must be worn during all shifts. Coming to work without your uniform may result in being sent home without pay."}, {"type": "bullet", "text": "No alterations, additions (pins, patches, writing), or modifications to uniform items are permitted."}, {"type": "bullet", "text": "The Gothamhalal hat or an approved head covering must be worn in the kitchen at all times."}, {"type": "note", "text": "Failure to maintain or return uniform items may result in disciplinary action up to and including termination."}, {"type": "paragraph", "text": "By signing below, I acknowledge receipt of the uniform items listed above, confirm I have read and understood the Uniform Policy, and agree to the terms stated in this agreement."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  OB-UA-001  ·  CONFIDENTIAL"}]'::jsonb, '{"Employee Signature","Manager Issuing Uniform"}'::text[], false),
  ('OB-TPA-001', 'onboarding', 'Tip Pool Acknowledgement and Agreement', '[{"type": "other", "role": null, "text": "Employee Full Name"}, {"type": "other", "role": null, "text": "Position"}, {"type": "other", "role": null, "text": "Start Date"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Date of This Agreement"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Employee Full Name", "Position", "Start Date"], ["", "", ""], ["Date of This Agreement", "", ""], ["", "", ""]]}, {"type": "heading", "level": "h1", "text": "Tip Pooling Policy Summary"}, {"type": "paragraph", "text": "Gothamhalal operates a mandatory tip pool for all employees working each shift. The following terms apply:"}, {"type": "bullet", "text": "<b><font color=''#b8960c''>1. Mandatory Participation.</font></b>  All employees — Cashier, Prep-er, Grill Master, and Manager (when performing non-supervisory duties) — participate in the tip pool for every shift worked."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>2. Tip Pool Distribution.</font></b>  All tips collected during a shift are pooled and divided equally among all employees working that shift. Each employee receives an equal share regardless of position."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>3. Collection.</font></b>  All cash tips and tips processed through the POS system are included in the pool. Managers collect and record all tips at the end of each shift."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>4. Payout Timing.</font></b>  Tips are paid out at the end of each shift or with the regular paycheck, as directed by management. Payout method will be communicated by your manager."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>5. Record Keeping.</font></b>  Management maintains records of all tip pool collections and distributions. You may request a copy of your tip records at any time."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>6. No Manager Retention.</font></b>  Managers who perform supervisory duties do not retain tips from the pool — this complies with the Fair Labor Standards Act (FLSA) and New York Labor Law."}, {"type": "bullet", "text": "<b><font color=''#b8960c''>7. Non-Retaliation.</font></b>  No employee will be retaliated against for raising questions or concerns about tip pool practices. Contact the Director of Operations at mario@gothamhalal.com."}, {"type": "heading", "level": "h1", "text": "Effective Date"}, {"type": "paragraph", "text": "This tip pool policy is effective January 1, 2025 and applies to all Gothamhalal locations."}, {"type": "heading", "level": "h1", "text": "Employee Acknowledgement"}, {"type": "paragraph", "text": "By signing below, I acknowledge that I have read, understood, and agree to participate in the Gothamhalal mandatory tip pool as described above. I understand that participation is a condition of employment and that any questions should be directed to my manager or the Director of Operations."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  OB-TPA-001  ·  CONFIDENTIAL"}]'::jsonb, '{"Employee Signature","Manager Witness"}'::text[], false),
