  ('OB-60D-001', 'onboarding', '60-Day Probationary Period Completion Form', '[{"type": "other", "role": null, "text": "Employee Name"}, {"type": "other", "role": null, "text": "Position"}, {"type": "other", "role": null, "text": "Employment Start Date"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "60-Day Completion Date"}, {"type": "other", "role": null, "text": "Reviewing Manager"}, {"type": "other", "role": null, "text": "Review Date"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Employee Name", "Position", "Employment Start Date"], ["", "", ""], ["60-Day Completion Date", "Reviewing Manager", "Review Date"], ["", "", ""]]}, {"type": "paragraph", "text": "Rating Scale:  1 = Unsatisfactory  |  2 = Needs Improvement  |  3 = Meets Expectations  |  4 = Exceeds Expectations  |  5 = Outstanding"}, {"type": "heading", "level": "h1", "text": "Full Probationary Performance Assessment"}, {"type": "other", "role": null, "text": "Evaluation Category"}, {"type": "other", "role": null, "text": "Rating (1–5)"}, {"type": "other", "role": null, "text": "Comments"}, {"type": "other", "role": null, "text": "<b>Attendance & Reliability</b>\nAll scheduled shifts attended; punctual and reliable."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Halal Standards</b>\nMaintains halal integrity at all times without exception."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Food Safety</b>\nConsistently follows food safety and sanitation procedures."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Station Mastery</b>\nPerforms primary station duties without supervision."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Customer Service</b>\nDelivers positive guest experiences consistently."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Team Collaboration</b>\nWorks effectively with all crew members."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Speed & Quality</b>\nMeets required speed benchmarks while maintaining quality."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Professionalism</b>\nMaintains professional attitude, appearance, and communication."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Following Policy</b>\nAdheres to all Gothamhalal policies without reminders."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "<b>Growth Potential</b>\nShows initiative and desire to improve."}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Evaluation Category", "Rating (1–5)", "Comments"], ["<b>Attendance & Reliability</b>\nAll scheduled shifts attended; punctual and reliable.", "", ""], ["<b>Halal Standards</b>\nMaintains halal integrity at all times without exception.", "", ""], ["<b>Food Safety</b>\nConsistently follows food safety and sanitation procedures.", "", ""], ["<b>Station Mastery</b>\nPerforms primary station duties without supervision.", "", ""], ["<b>Customer Service</b>\nDelivers positive guest experiences consistently.", "", ""], ["<b>Team Collaboration</b>\nWorks effectively with all crew members.", "", ""], ["<b>Speed & Quality</b>\nMeets required speed benchmarks while maintaining quality.", "", ""], ["<b>Professionalism</b>\nMaintains professional attitude, appearance, and communication.", "", ""], ["<b>Following Policy</b>\nAdheres to all Gothamhalal policies without reminders.", "", ""], ["<b>Growth Potential</b>\nShows initiative and desire to improve.", "", ""]]}, {"type": "heading", "level": "h1", "text": "Probationary Period Outcome"}, {"type": "paragraph", "text": "☐ <b>Successfully Completed</b> — Employee has demonstrated competency and meets Gothamhalal standards. Transition to regular employment status effective immediately.\n\n☐ <b>Extended Probation</b> — Employee requires additional time. New review date: _______________\n\n☐ <b>Employment Terminated</b> — Employee has not met minimum standards during the probationary period."}, {"type": "paragraph", "text": "Manager Comments:"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "paragraph", "text": "__________________________________________________________________________________________"}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  OB-60D-001  ·  CONFIDENTIAL"}]'::jsonb, '{"Manager Signature","Employee Signature","Director of Operations (if outcome is termination)"}'::text[], false),
  ('OB-FWT-001', 'onboarding', 'First Week Training Schedule', '[{"type": "paragraph", "text": "Purpose: Provide every new Gothamhalal team member with a structured, consistent first-week experience that covers brand standards, halal integrity, food safety, station training, and operational expectations before independent work begins."}, {"type": "paragraph", "text": "Trainer: Assigned manager or lead trainer only. Do not assign independent shifts until Week 2."}, {"type": "other", "role": null, "text": "Employee Name"}, {"type": "other", "role": null, "text": "Position"}, {"type": "other", "role": null, "text": "Start Date"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Assigned Trainer"}, {"type": "other", "role": null, "text": "Location"}, {"type": "other", "role": null, "text": "Shift"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Employee Name", "Position", "Start Date"], ["", "", ""], ["Assigned Trainer", "Location", "Shift"], ["", "", ""]]}, {"type": "heading", "level": "h1", "text": "Day 1 — Monday: Orientation & Foundations"}, {"type": "other", "role": null, "text": "Time"}, {"type": "other", "role": null, "text": "Activity"}, {"type": "other", "role": null, "text": "9:00–10:00 AM"}, {"type": "other", "role": null, "text": "Manager welcome, HR paperwork, handbook review, uniform issued"}, {"type": "other", "role": null, "text": "10:00–11:00 AM"}, {"type": "other", "role": null, "text": "Halal Standards Training (TR-HAL-001) — required before any kitchen work"}, {"type": "other", "role": null, "text": "11:00 AM–12:00 PM"}, {"type": "other", "role": null, "text": "Food Safety & Sanitation Training (TR-FS-001)"}, {"type": "other", "role": null, "text": "12:00–2:00 PM"}, {"type": "other", "role": null, "text": "Location tour, station overview, shadowing trainer on shift"}, {"type": "other", "role": null, "text": "2:00–3:00 PM"}, {"type": "other", "role": null, "text": "POS system introduction — observation only, no live transactions"}, {"type": "other", "role": null, "text": "End of Day"}, {"type": "other", "role": null, "text": "Manager check-in: questions, schedule confirmed, trainer introduced"}, {"type": "table", "rows": [["Time", "Activity"], ["9:00–10:00 AM", "Manager welcome, HR paperwork, handbook review, uniform issued"], ["10:00–11:00 AM", "Halal Standards Training (TR-HAL-001) — required before any kitchen work"], ["11:00 AM–12:00 PM", "Food Safety & Sanitation Training (TR-FS-001)"], ["12:00–2:00 PM", "Location tour, station overview, shadowing trainer on shift"], ["2:00–3:00 PM", "POS system introduction — observation only, no live transactions"], ["End of Day", "Manager check-in: questions, schedule confirmed, trainer introduced"]]}, {"type": "heading", "level": "h1", "text": "Day 2 — Tuesday: Station Introduction"}, {"type": "other", "role": null, "text": "Time"}, {"type": "other", "role": null, "text": "Activity"}, {"type": "other", "role": null, "text": "Full Shift"}, {"type": "other", "role": null, "text": "Shadow trainer at assigned primary station"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "Begin practicing station tasks under direct trainer supervision"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "No independent customer transactions yet"}, {"type": "other", "role": null, "text": "End of Day"}, {"type": "other", "role": null, "text": "Trainer feedback — note strengths and areas to develop"}, {"type": "table", "rows": [["Time", "Activity"], ["Full Shift", "Shadow trainer at assigned primary station"], ["", "Begin practicing station tasks under direct trainer supervision"], ["", "No independent customer transactions yet"], ["End of Day", "Trainer feedback — note strength