  ('OPS-MGR-001', 'operations', 'Manager Shift Checklist', '[{"type": "heading", "level": "h1", "text": "Start of Shift — First 30 Minutes"}, {"type": "table", "rows": [["Task"], ["Review previous shift''s notes and any flagged issues from closing checklist"], ["Verify all scheduled crew are present and in full Gothamhalal uniform"], ["Clock in all employees — confirm schedule matches actual staff on floor"], ["DAILY LINEUP (Required — 5 min): (1) Share a wow story from last shift (2) State today''s focus goal (3) Announce any specials (4) Confirm all stations ready"], ["Verify opening cash drawer has been properly counted and initialed by both parties"], ["Confirm all stations are stocked and fully ready for service"], ["HALAL CHECK: Walk the kitchen — confirm all products are labeled and certified halal"], ["Check temperature logs from prior shift are filled in correctly"]]}, {"type": "heading", "level": "h1", "text": "Mid-Shift — Ongoing Responsibilities"}, {"type": "table", "rows": [["Task"], ["Food temperature checks — complete Food Safety Temperature Log every 2 hours"], ["Monitor line speed — adjust crew positioning as needed during rush periods"], ["Walk floor every 30 minutes — cleanliness, customer experience, crew conduct"], ["Address any customer complaints immediately and log them (OPS-CCL-001)"], ["Monitor cell phone policy — no phones on floor during service"], ["Check trash levels — empty before overflow"], ["Verify restrooms are clean — check hourly during peak hours"], ["Manage crew breaks in compliance with NY labor law (30 min for shifts over 6 hours)"], ["Monitor inventory levels mid-shift — request restocking as needed"], ["Ensure tip pool is being tracked per Gothamhalal tip pool policy"]]}, {"type": "heading", "level": "h1", "text": "Halal Integrity — Mandatory Checks Every Shift"}, {"type": "table", "rows": [["Task"], ["All halal-certified meat stored separately and clearly labeled"], ["No cross-contamination observed between halal products 