  ('OPS-CASH-001', 'operations', 'Cash Reconciliation & Drawer Count', '[{"type": "paragraph", "text": "Date / Shift (Morning 11am–4pm or Evening 4pm–12am) / Time. Manager Counting / Witness — record names."}, {"type": "heading", "level": "h1", "text": "Step 1 — Count Physical Cash in Drawer"}, {"type": "table", "rows": [["Bill / Coin Denomination", "Quantity", "Subtotal ($)"], ["$100 bills", "", ""], ["$50 bills", "", ""], ["$20 bills", "", ""], ["$10 bills", "", ""], ["$5 bills", "", ""], ["$1 bills", "", ""], ["Quarters ($0.25)", "", ""], ["Dimes ($0.10)", "", ""], ["Nickels ($0.05)", "", ""], ["Pennies ($0.01)", "", ""], ["TOTAL CASH IN DRAWER", "", ""]]}, {"type": "heading", "level": "h1", "text": "Step 2 — Reconciliation"}, {"type": "table", "rows": [["Line Item", "Amount ($)"], ["Total cash counted in drawer (from Step 1)", ""], ["Less: Opening float / starting cash", "( )"], ["Net Cash Received This Shift", "$"], ["Total cash sales per POS system", ""], ["Total card / digital sales per POS (for reference only)", ""], ["Total refunds issued (cash)", "( )"], ["Voids", "( )"], ["Net Expected Cash Sales", "$"], ["VARIANCE (Over / Short) — carry to Step 3", "$"]]}, {"type": "heading", "level": "h1", "text": "Step 3 — Variance Tier — Check One"}, {"type": "note", "text": "Per Q1 2026 Quarterly Planning Meeting: Apply the correct tier below based on actual variance amount."}, {"type": "table", "rows": [["Variance Amount", "Action Required"], ["$0.01 – $5.00", "Record on this form only. Note cause if known. No further action if isolated."], ["$5.01 – $10.00", "Report to Director of Operations same shift. Document explanation below."], ["$10.00 – $50.00", "Formal written notice issued to cashier. Employee and manager both sign. DOO receives copy."], ["Over $50.00 / Repeated", "Immediate investigation. Director of Operations notified this shift."], ["Suspected theft / intentional", "ZERO TOLERANCE — Immediate escalation. Contact DOO before or immediately after action."]]}, {"type": "paragraph", "text": "Variance explanation (required for $5.01 and above) — free text. Director of Operations notified: Yes (Date/Time) or No (Not required)."}, {"type": "heading", "level": "h1", "text": "Step 4 — Tip Pool Reconciliation"}, {"type": "paragraph", "text": "Per Gothamhalal policy: Tips are distributed equally per eligible crew member per shift. Managers are excluded from the tip pool."}, {"type": "table", "rows": [["Item", "Amount ($)"], ["Total tips collected (cash) this shift", ""], ["Total tips collected (card / digital) this shift", ""], ["Total Tips This Shift", "$"], ["Number of crew members sharing tip pool this shift", ""], ["Tip per crew member ($)", "$"]]}, {"type": "heading", "level": "h1", "text": "Step 5 — Cash Disposition"}, {"type": "table", "rows": [["Item", "Amount ($)"], ["Amount placed in safe / bank deposit", ""], ["Restock float for next shift (standard float amount)", ""], ["Accounted For Total", "$"]]}]'::jsonb, '{"Manager Counting","Witness / Second Counter (if applicable)"}'::text[], true),
