r", "role": null, "text": "TR-HAL-001"}, {"type": "other", "role": null, "text": "Halal Food Standards & Handling Training"}, {"type": "other", "role": null, "text": "Day 1"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-FS-001"}, {"type": "other", "role": null, "text": "Food Safety & Sanitation Training"}, {"type": "other", "role": null, "text": "Day 1"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-GRILL-001"}, {"type": "other", "role": null, "text": "Grill Master Training (kitchen staff)"}, {"type": "other", "role": null, "text": "Days 2–4"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-PREP-001"}, {"type": "other", "role": null, "text": "Prep Station Training (kitchen staff)"}, {"type": "other", "role": null, "text": "Days 2–4"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-POS-CSH-001"}, {"type": "other", "role": null, "text": "Cashier / Hospitality Training"}, {"type": "other", "role": null, "text": "Days 2–4"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-POS-001"}, {"type": "other", "role": null, "text": "POS System General Training"}, {"type": "other", "role": null, "text": "Days 3–4"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-CASH-001"}, {"type": "other", "role": null, "text": "Cash Handling Guide"}, {"type": "other", "role": null, "text": "Day 4"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-CS-001"}, {"type": "other", "role": null, "text": "Customer Service Training"}, {"type": "other", "role": null, "text": "Day 5"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "TR-MGR-001"}, {"type": "other", "role": null, "text": "Manager Training Guide (managers only)"}, {"type": "other", "role": null, "text": "Days 6–10