, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "All lights off except required security lighting"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "Lock all entrances and exits"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "Arm alarm if applicable"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": "☐"}, {"type": "other", "role": null, "text": "Note any supply needs or maintenance issues in manager report"}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Done", "Task", "Mgr Init"], ["☐", "Verify all cooking equipment is powered OFF", ""], ["☐", "Verify all refrigeration is closed and functioning", ""], ["☐", "All lights off except required security lighting", ""], ["☐", "Lock all entrances and exits", ""], ["☐", "Arm alarm if applicable", ""], ["☐", "Note any supply needs or maintenance issues in manager report", ""]]}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  OPS-CLOSE-001 / TR  ·  CONFIDENTIAL"}]'::jsonb, '{"Closing Manager Signature","Time Location Secured"}'::text[], false),
  ('TR-DCG-001', 'training', 'How to Handle Difficult Customers', '[{"type": "paragraph", "text": "Key Principle: Stay calm. De-escalate. Involve management when needed. Never argue."}, {"type": "paragraph", "text": "The Gothamhalal Recovery Standard: How we handle a problem tells customers more about who we are than the problem itself."}, {"type": "heading", "level": "h1", "text": "The LAST Framework"}, {"type": "other", "role": null, "text": "Step"}, {"type": "other", "role": null, "text": "What It Means"}, {"type": "other", "role": null, "text": "Example"}, {"type": "other", "role": null, "text": "L — Listen"}, {"type": "other", "role": null, "text": "Let the customer speak without interrupting. Do not defend."}, {"type": "other", "role": null, "text": "\"I hear you. Tell me what happened.\""}, {"type": "other", "role": null, "text": "A — Acknowledge"}, {"type": "other", "role": null, "text": "Validate their frustration. Do not blame them or your team."}, {"type": "other", "role": null, "text": "\"I completely understand why you''re upset.\""}, {"type": "other", "role": null, "text": "S — Solve"}, {"type": "other", "role": null, "text": "Offer a clear solution. Remake, refund, or escalate to manager."}, {"type": "other", "role": null, "text": "\"Let me remake that for you right now.\""}, {"type": "other", "role": null, "text": "T — Thank"}, {"type": "other", "role": null, "text": "Thank the customer for telling you. Every complaint is a chance to improve."}, {"type": "other", "role": null, "text": "\"Thank you for letting us know. We''ll make sure this doesn''t happen again.\""}, {"type": "table", "rows": [["Step", "What It Means", "Example"], ["L — Listen", "Let the customer speak without interrupting. Do not defend.", "\"I hear you. Tell me what happened.\""], ["A — Acknowledge", "Validate their frustration. Do not blame them or your team.", "\"I completely understand why you''re upset.\""], ["S — Solve", "Offer a clear solution. Remake, refund, or escalate to manager.", "\"Let me remake that for you right now.\""], ["T — Thank", "Thank the customer for telling you. Every complaint is a chance to improve.", "\"Thank you for letting us know. We''ll make sure this doesn''t happen again.\""]]}, {"type": "heading", "level": "h1", "text": "Scenario Responses"}, {"type": "other", "role": null, "text": "Situation"}, {"type": "other", "role": null, "text": "Response"}, {"type": "other", "role": null, "text": "Wrong order"}, {"type": "other", "role": null, "text": "Apologize, take the item back, remake correctly at no charge. Do not argue about what was ordered."}, {"type": "other", "role": null, "text": "Long wait time"}, {"type": "other", "role": null, "text": "Acknowledge the wait proactively. Give an honest ETA. Offer a drink or side if wait exceeds 10 minutes."}, {"type": "other", "role": null, "text": "Customer says food is cold"}, {"type": "other", "role": null, "text": "Apologize and offer to reheat or remake. Do not question whether it was actually cold."}, {"type": "other", "role": null, "text": "Customer is aggressive or yelling"}, {"type": "other", "role": null, "text": "Stay calm and keep your voice low. Do not raise your voice. Call manager immediately — do not engage in an argument."}, {"type": "other", "role": null, "text": "Customer demands a refund"}, {"type": "other", "role": null, "text": "Managers only handle refunds. Call your manager. Do not issue a refund yourself."}, {"type": "other", "role": null, "text": "Halal question from customer"}, {"type": "other", "role": null, "text": "Answer honestly what you know. If unsure, call a manager. Never guess about halal status."}, {"type": "table", "rows": [["Situation", "Response"], ["Wrong order", "Apologize, take the item back, remake correctly at no charge. Do not argue about what was ordered."], ["Long wait time", "Acknowledge the wait proactively. Give an honest ETA. Offer a drink or side if wait exceeds 10 minutes."], ["Customer says food is cold", "Apologize and offer to reheat or remake. Do not question whether it was actually cold."], ["Customer is aggressive or yelling", "Stay calm and keep your voice low. Do not raise your voice. Call manager immediately — do not engage in an argument."], ["Customer demands a refund", "Managers only handle refunds. Call your manager. Do not issue a refund yourself."], ["Halal question from customer", "Answer honestly what you know. If unsure, call a manager. Never guess about halal status."]]}, {"type": "heading", "level": "h1", "text": "When to Involve Management — Immediately"}, {"type": "bullet", "text": "Customer becomes physically aggressive or threatening"}, {"type": "bullet", "text": "Customer requests a full refund"}, {"type": "bullet", "text": "Any complaint involving halal integrity or food safety"}, {"type": "bullet", "text": "Situation is not resolved after your first attempt"}, {"type": "bullet", "text": "Customer threatens to contact health department or post online"}, {"type": "heading", "level": "h1", "text": "What You Must Never Do"}, {"type": "bullet", "text": "✗  Argue with a customer — even if you know you are right"}, {"type": "bullet", "text": "✗  Issue a refund without manager authorization"}, {"type": "bullet", "text": "✗  Deny a halal concern without checking with management"}, {"type": "bullet", "text": "✗  Walk away from an upset customer without notifying management"}, {"type": "bullet", "text": "✗  Post about a customer interaction on social media"}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  TR-DCG-001  ·  CONFIDENTIAL"}]'::jsonb, '{"Trainer Sign-Off","Employee Signature"}'::text[], false),
  ('TR-FHC-001', 'training', 'Food Handler Certification Requirements — New York State', '[{"type": "paragraph", "text": "Gothamhalal operates in New York State and is committed to full compliance with all applicable food safety certification requirements. This document outlines certification requirements for all positions."}, {"type": "heading", "level": "h1", "text": "New York State Requirements"}, {"type": "other", "role": null, "text": "Requirement"}, {"type": "other", "role": null, "text": "Who"}, {"type": "other", "role": null, "text": "Standard"}, {"type": "other", "role": null, "text": "Food Protection Manager (FPM)"}, {"type": "other", "role": null, "text": "At least one certified FPM must be on duty during ALL hours of operation"}, {"type": "other", "role": null, "text": "NYS Dept of Health — required for permit"}, {"type": "other", "role": null, "text": "Accepted Certifications"}, {"type": "other", "role": null, "text": "ServSafe Food Protection Manager, or equivalent approved by NYS DOH"}, {"type": "other", "role": null, "text": "Must be renewed per certification schedule"}, {"type": "other", "role": null, "text": "Food Handler Training"}, {"type": "other", "role": null, "text": "All other employees"}, {"type": "other", "role": null, "text": "Must complete food safety training before working with food (this document fulfills general training)"}, {"type": "table", "rows": [["Requirement", "Who", "Standard"], ["Food Protection Manager (FPM)", "At least one certified FPM must be on duty during ALL hours of operation", "NYS Dept of Health — required for permit"], ["Accepted Certifications", "ServSafe Food Protection Manager, or equivalent approved by NYS DOH", "Must be renewed per certification schedule"], ["Food Handler Training", "All other employees", "Must complete food safety training before working with food (this document fulfills general training)"]]}, {"type": "heading", "level": "h1", "text": "Accepted Certification Programs (NYS DOH Approved)"}, {"type": "other", "role": null, "text": "Program"}, {"type": "other", "role": null, "text": "Details"}, {"type": "other", "role": null, "text": "ServSafe"}, {"type": "other", "role": null, "text": "National Restaurant Association — most widely used. Available online and in-person."}, {"type": "other", "role": null, "text": "360training.com"}, {"type": "other", "role": null, "text": "Online option — accepted in NY for food handler level."}, {"type": "other", "role": null, "text": "NYC DOHMH Food Protection Course"}, {"type": "other", "role": null, "text": "Required for NYC locations — free, 15-hour course, exam required."}, {"type": "other", "role": null, "text": "Other NYS-approved programs"}, {"type": "other", "role": null, "text": "Check with Director of Operations for the current approved list."}, {"type": "table", "rows": [["Program", "Details"], ["ServSafe", "National Restaurant Association — most widely used. Available online and in-person."], ["360training.com", "Online option — accepted in NY for food handler level."], ["NYC DOHMH Food Protection Course", "Required for NYC locations — free, 15-hour course, exam required."], ["Other NYS-approved programs", "Check with Director of Operations for the current approved list."]]}, {"type": "heading", "level": "h1", "text": "Gothamhalal Certification Tracking"}, {"type": "other", "role": null, "text": "Employee Name"}, {"type": "other", "role": null, "text": "Certification Type"}, {"type": "other", "role": null, "text": "Certification #"}, {"type": "other", "role": null, "text": "Issue Date"}, {"type": "other", "role": null, "text": "Expiration Date"}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "other", "role": null, "text": ""}, {"type": "table", "rows": [["Employee Name", "Certification Type", "Certification #", "Issue Date", "Expiration Date"], ["", "", "", "", ""], ["", "", "", "", ""], ["", "", "", "", ""], ["", "", "", "", ""], ["", "", "", "", ""]]}, {"type": "heading", "level": "h1", "text": "Important Notes"}, {"type": "bullet", "text": "If the on-duty Food Protection Manager leaves mid-shift, management must immediately ensure another FPM-certified employee covers."}, {"type": "bullet", "text": "Expired certifications are not valid — arrange renewal at least 30 days before expiration."}, {"type": "bullet", "text": "Gothamhalal will reimburse the cost of approved food safety certifications — see Director of Operations for details."}, {"type": "bullet", "text": "All certifications must be on file with the Director of Operations and available for health department inspection."}, {"type": "other", "role": "footer", "text": "GOTHAMHALAL  ·  hello@gothamhalal.com  ·  gothamhalal.com  ·  TR-FHC-001  ·  CONFIDENTIAL"}]'::jsonb, '{"Manager","Director of Operations"}'::text[], false),
